pub fn addr(&self) -> usize {
        self.bits
    }
}
/// Set the TLB refill entry.
/// # Warning!
/// The `val` must be page aligned.

pub fn set_tlbrentry(addr: usize) {
    assert_eq!(addr & 0xFFF, 0);
    write_csr_loong!(0x88, addr);
}
